    <script>
        // Custom color palette
        const colors = {
            blue: '#3b82f6',
            purple: '#a78bfa',
            green: '#22c55e',
            amber: '#f59e0b',
            red: '#ef4444',
            slate: '#64748b'
        };

        async function loadDashboard() {
            try {
                const response = await fetch('data.json');
                const data = await response.json();

                document.getElementById('lastSync').textContent = new Date().toLocaleString();

                // 1. Process Metrics
                const total = data.length;
                const resolved = data.filter(t => t.Status === 'Closed' || t.Status === 'Resolved').length;
                const pending = total - resolved;

                document.getElementById('totalTickets').textContent = total.toLocaleString();
                document.getElementById('resolvedRate').textContent = ((resolved / total) * 100).toFixed(1) + '%';
                document.getElementById('pendingTickets').textContent = pending.toLocaleString();

                // 2. Pain Point Analysis (AI-like)
                const keywords = [
                    { key: 'Notepad', label: 'Thai Character Encoding Issue', color: 'red', icon: 'font' },
                    { key: 'Oracle', label: 'Oracle IE Mode Compatibility', color: 'amber', icon: 'database' },
                    { key: 'Hardware-MA', label: 'Aging Hardware (Asset Refresh)', color: 'blue', icon: 'laptop' },
                    { key: 'MFA', label: 'Authentication/MFA Locks', color: 'purple', icon: 'key' }
                ];

                const painPointsDiv = document.getElementById('painPointsList');
                keywords.forEach(k => {
                    const count = data.filter(t => JSON.stringify(t).includes(k.key)).length;
                    const percent = ((count / total) * 100).toFixed(1);

                    const el = document.createElement('div');
                    el.className = `p-4 rounded-xl bg-${k.color}-500/10 border border-${k.color}-500/20 flex items-center gap-4`;
                    el.innerHTML = `
                        <div class="h-10 w-10 rounded-full bg-${k.color}-500/20 flex items-center justify-center text-${k.color}-400">
                            <i class="fas fa-${k.icon}"></i>
                        </div>
                        <div class="flex-1">
                            <p class="text-sm font-bold text-${k.color}-400">${k.label}</p>
                            <div class="w-full bg-slate-700 h-1.5 rounded-full mt-2">
                                <div class="bg-${k.color}-500 h-1.5 rounded-full" style="width: ${percent}%"></div>
                            </div>
                        </div>
                        <div class="text-right">
                            <p class="text-xs font-bold text-slate-500">${count} Tickets</p>
                            <p class="text-xs text-slate-400">${percent}%</p>
                        </div>
                    `;
                    painPointsDiv.appendChild(el);
                });

                // 3. Distribution Charts
                const buMap = {};
                const catMap = {};
                const trendMap = {};

                data.forEach(t => {
                    // BU
                    buMap[t['BU Name']] = (buMap[t['BU Name']] || 0) + 1;
                    // Category
                    const cat = t.Category.split('-')[0];
                    catMap[cat] = (catMap[cat] || 0) + 1;
                    // Trend (Daily)
                    if (t['Resolved Date']) {
                        const date = t['Resolved Date'].split(' ')[0];
                        trendMap[date] = (trendMap[date] || 0) + 1;
                    }
                });

                // Charts Configuration
                const chartConfig = (type, labels, data, color) => ({
                    type: type,
                    data: {
                        labels: labels,
                        datasets: [{
                            data: data,
                            borderColor: color,
                            backgroundColor: type === 'line' ? color + '22' : color + 'aa',
                            borderWidth: 2,
                            tension: 0.4,
                            fill: true,
                            pointRadius: 3,
                        }]
                    },
                    options: {
                        responsive: true,
                        maintainAspectRatio: false,
                        plugins: { legend: { display: false } },
                        scales: {
                            y: { grid: { color: 'rgba(255,255,255,0.05)' }, ticks: { color: '#64748b' } },
                            x: { grid: { display: false }, ticks: { color: '#64748b' } }
                        }
                    }
                });

                // Trend Line
                const sortedDates = Object.keys(trendMap).sort().slice(-14);
                new Chart(document.getElementById('trendChart'), chartConfig('line', sortedDates, sortedDates.map(d => trendMap[d]), colors.blue));

                // BU Bar
                const topBUs = Object.entries(buMap).sort((a,b) => b[1]-a[1]).slice(0, 6);
                new Chart(document.getElementById('buChart'), chartConfig('bar', topBUs.map(x=>x[0]), topBUs.map(x=>x[1]), colors.green));

                // Category Bar
                const topCats = Object.entries(catMap).sort((a,b) => b[1]-a[1]).slice(0, 6);
                new Chart(document.getElementById('categoryChart'), chartConfig('bar', topCats.map(x=>x[0]), topCats.map(x=>x[1]), colors.purple));

                // 4. Activity Feed
                const feed = document.getElementById('recentActivity');
                data.slice(0, 15).forEach(t => {
                    const item = document.createElement('div');
                    item.className = 'p-3 rounded-xl bg-slate-800/50 border border-slate-700/50 flex items-start gap-3 text-sm';
                    item.innerHTML = `
                        <div class="mt-1 h-2 w-2 rounded-full ${t.Status === 'Closed' ? 'bg-green-500' : 'bg-amber-500'}"></div>
                        <div class="flex-1">
                            <p class="font-bold text-slate-200 line-clamp-1">${t.Subject}</p>
                            <div class="flex justify-between mt-1 text-xs text-slate-500">
                                <span>${t['BU Name']}</span>
                                <span>${t.ID}</span>
                            </div>
                        </div>
                    `;
                    feed.appendChild(item);
                });

            } catch (err) {
                console.error("Dashboard failed to load:", err);
            }
        }

        loadDashboard();
    </script>
</body>
