                        <i class="fas fa-list-check"></i> Agent Workload Breakdown
                    </h3>
                    <div class="overflow-x-auto">
                        <table class="w-full text-left text-sm text-slate-300">
                            <thead>
                                <tr class="text-slate-500 border-b border-slate-700">
                                    <th class="px-4 py-3">Agent Name</th>
                                    <th class="px-4 py-3">Total Work</th>
                                    <th class="px-4 py-3">Primary BU</th>
                                    <th class="px-4 py-3 text-right">Activity Level</th>
                                </tr>
                            </thead>
                            <tbody id="agentTable">
                                <!-- JS -->
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>

            <!-- Side Panel: Recent Actions & Insights -->
            <div class="space-y-8">
                <div class="glass-card p-6 rounded-2xl border-t-4 border-blue-500">
                    <h3 class="text-lg font-bold mb-4 flex items-center gap-2">
                        <i class="fas fa-bolt text-blue-400"></i> Recent Actions
                    </h3>
                    <div class="space-y-4 max-h-[600px] overflow-y-auto pr-2" id="actionFeed">
                        <!-- JS -->
                    </div>
                </div>

                <div class="glass-card p-6 rounded-2xl bg-blue-500/5">
                    <h3 class="text-lg font-bold mb-2">Agent Insight</h3>
                    <p class="text-sm text-slate-400 leading-relaxed">
                        The "Action by" data indicates a high concentration of work among the top 5 agents. 
                        Consider redistributing tasks to prevent burnout and ensure consistent SLA across all towers.
                    </p>
                </div>
            </div>

        </div>

        <footer class="mt-12 pt-8 border-t border-slate-800 text-center text-slate-500 text-sm">
            <p>© 2026 IT Operations Personnel Analysis | Last Sync: <span id="lastSync">---</span></p>
        </footer>
    </div>

    <script>
        async function loadDashboard() {
            try {
                const response = await fetch('data.json');
                const data = await response.json();
                document.getElementById('lastSync').textContent = new Date().toLocaleString();

                // 1. Process "Action by" Data
                const actionByMap = {};
                data.forEach(t => {
                    const agent = t['Action by'] || 'Unknown';
                    if (!actionByMap[agent]) {
                        actionByMap[agent] = { count: 0, bu: {}, lastId: '' };
                    }
                    actionByMap[agent].count++;
                    actionByMap[agent].bu[t['BU Name']] = (actionByMap[agent].bu[t['BU Name']] || 0) + 1;
                });

                const sortedAgents = Object.entries(actionByMap)
                    .sort((a, b) => b[1].count - a[1].count);

                // 2. Metrics
                document.getElementById('totalTickets').textContent = data.length.toLocaleString();
                document.getElementById('activeAgents').textContent = Object.keys(actionByMap).length;
                document.getElementById('topPerformer').textContent = sortedAgents[0][0];
                document.getElementById('avgWorkload').textContent = Math.round(data.length / Object.keys(actionByMap).length);

                // 3. Agent Chart
                const top10 = sortedAgents.slice(0, 10);
                new Chart(document.getElementById('agentChart'), {
                    type: 'bar',
                    data: {
                        labels: top10.map(a => a[0]),
                        datasets: [{
                            label: 'Resolved Tickets',
                            data: top10.map(a => a[1].count),
                            backgroundColor: '#3b82f6aa',
                            borderColor: '#3b82f6',
                            borderWidth: 1,
                            borderRadius: 8
                        }]
                    },
                    options: {
                        indexAxis: 'y',
                        responsive: true,
                        maintainAspectRatio: false,
                        plugins: { legend: { display: false } },
                        scales: {
                            x: { grid: { color: 'rgba(255,255,255,0.05)' }, ticks: { color: '#64748b' } },
                            y: { grid: { display: false }, ticks: { color: '#f8fafc' } }
                        }
                    }
                });

                // 4. Agent Table
                const table = document.getElementById('agentTable');
                sortedAgents.slice(0, 15).forEach(([name, info]) => {
                    const primaryBU = Object.entries(info.bu).sort((a,b) => b[1]-a[1])[0][0];
                    const row = document.createElement('tr');
                    row.className = 'border-b border-slate-800 hover:bg-slate-800/30 transition-colors';
                    row.innerHTML = `
                        <td class="px-4 py-4 font-bold text-white">${name}</td>
                        <td class="px-4 py-4">${info.count}</td>
                        <td class="px-4 py-4 text-xs text-slate-500">${primaryBU}</td>
                        <td class="px-4 py-4 text-right">
                            <span class="px-2 py-1 rounded bg-blue-500/10 text-blue-400 text-xs font-bold">
                                ${((info.count / data.length) * 100).toFixed(1)}%
                            </span>
                        </td>
                    `;
                    table.appendChild(row);
                });

                // 5. Action Feed
                const feed = document.getElementById('actionFeed');
                data.slice(0, 20).forEach(t => {
                    const item = document.createElement('div');
                    item.className = 'p-4 rounded-xl bg-slate-800/40 border border-slate-700/50 flex items-start gap-4';
                    item.innerHTML = `
                        <div class="h-10 w-10 rounded-full bg-blue-500/10 flex items-center justify-center text-blue-400 shrink-0">
                            <i class="fas fa-user-check"></i>
                        </div>
                        <div class="flex-1 overflow-hidden">
                            <p class="font-bold text-slate-200 truncate">${t['Action by'] || 'N/A'}</p>
                            <p class="text-xs text-slate-500 mt-1 line-clamp-1">${t.Subject}</p>
                            <div class="flex justify-between items-center mt-2">
                                <span class="text-[10px] text-slate-600 font-mono">${t.ID}</span>
                                <span class="text-[10px] px-1.5 py-0.5 bg-slate-700 rounded text-slate-400 uppercase font-bold">${t['BU Name']}</span>
                            </div>
                        </div>
                    `;
                    feed.appendChild(item);
                });

            } catch (err) {
                console.error("Agent Dashboard Error:", err);
            }
        }
        loadDashboard();
    </script>
</body>

</html>

