    <script>
        let rawData = [];
        let filteredData = [];
        let trendChart, performanceChart;
        const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

        async function init() {
            try {
                const response = await fetch('data.json');
                rawData = await response.json();
                document.getElementById('globalTotal').textContent = rawData.length.toLocaleString();

                populateFilters();
                applyFilters();

                // Add event listeners
                document.getElementById('filterMonth').addEventListener('change', applyFilters);
                document.getElementById('filterAgentGroup').addEventListener('change', applyFilters);
                document.getElementById('filterActionBy').addEventListener('change', applyFilters);
            } catch (err) {
                console.error("Initialization error:", err);
            }
        }

        function populateFilters() {
            const months = new Set();
            const agentGroups = new Set();
            const actionBys = new Set();

            rawData.forEach(t => {
                if (t['Resolved Date']) {
                    const date = new Date(t['Resolved Date']);
                    const mKey = `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}`;
                    months.add(mKey);
                }
                if (t['Agent Name']) agentGroups.add(t['Agent Name']);
                if (t['Action by']) actionBys.add(t['Action by']);
            });

            const monthSelect = document.getElementById('filterMonth');
            Array.from(months).sort().forEach(m => {
                const [y, mm] = m.split('-');
                const opt = document.createElement('option');
                opt.value = m;
                opt.textContent = `${monthNames[parseInt(mm)-1]} ${y}`;
                monthSelect.appendChild(opt);
            });

            const agentSelect = document.getElementById('filterAgentGroup');
            Array.from(agentGroups).sort().forEach(a => {
                const opt = document.createElement('option');
                opt.value = a;
                opt.textContent = a;
                agentSelect.appendChild(opt);
            });

            const actionSelect = document.getElementById('filterActionBy');
            Array.from(actionBys).sort().forEach(a => {
                const opt = document.createElement('option');
                opt.value = a;
                opt.textContent = a;
                actionSelect.appendChild(opt);
            });
        }

        function applyFilters() {
            const mVal = document.getElementById('filterMonth').value;
            const agVal = document.getElementById('filterAgentGroup').value;
            const abVal = document.getElementById('filterActionBy').value;

            filteredData = rawData.filter(t => {
                let match = true;
                if (mVal !== 'all' && t['Resolved Date']) {
                    const date = new Date(t['Resolved Date']);
                    const mKey = `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}`;
                    if (mKey !== mVal) match = false;
                }
                if (agVal !== 'all' && t['Agent Name'] !== agVal) match = false;
                if (abVal !== 'all' && t['Action by'] !== abVal) match = false;
                return match;
            });

            updateUI();
        }

        function updateUI() {
            document.getElementById('filteredTotal').textContent = filteredData.length.toLocaleString();

            updateCharts();
            updateTable();
        }

        function updateCharts() {
            const trendMap = {};
            const perfMap = {};

            filteredData.forEach(t => {
                // Trend (By Date)
                if (t['Resolved Date']) {
                    const d = t['Resolved Date'].split(' ')[0];
                    trendMap[d] = (trendMap[d] || 0) + 1;
                }
                // Performance (By Action by)
                const name = t['Action by'] || 'Unknown';
                perfMap[name] = (perfMap[name] || 0) + 1;
            });

            const trendLabels = Object.keys(trendMap).sort();
            const perfLabels = Object.entries(perfMap).sort((a,b) => b[1]-a[1]).slice(0, 10);

            if (trendChart) trendChart.destroy();
            if (performanceChart) performanceChart.destroy();

            trendChart = new Chart(document.getElementById('trendChart'), {
                type: 'line',
                data: {
                    labels: trendLabels,
                    datasets: [{
                        label: 'Tickets',
                        data: trendLabels.map(l => trendMap[l]),
                        borderColor: '#3b82f6',
                        tension: 0.3,
                        fill: true,
                        backgroundColor: 'rgba(59, 130, 246, 0.1)'
                    }]
                },
                options: { maintainAspectRatio: false, plugins: { legend: { display: false } } }
            });

            performanceChart = new Chart(document.getElementById('performanceChart'), {
                type: 'bar',
                data: {
                    labels: perfLabels.map(p => p[0]),
                    datasets: [{
                        data: perfLabels.map(p => p[1]),
                        backgroundColor: '#22c55e'
                    }]
                },
                options: { maintainAspectRatio: false, plugins: { legend: { display: false } }, indexAxis: 'y' }
            });
        }

        function updateTable() {
            const tbody = document.getElementById('logTableBody');
            tbody.innerHTML = '';
            filteredData.slice(0, 50).forEach(t => {
                const tr = document.createElement('tr');
                tr.className = 'border-b border-slate-800 hover:bg-slate-800/30';
                tr.innerHTML = `
                    <td class="px-4 py-3 text-xs">${t['Resolved Date'] || 'N/A'}</td>
                    <td class="px-4 py-3 font-mono text-xs">${t.ID}</td>
                    <td class="px-4 py-3 text-white font-bold">${t['Action by'] || 'N/A'}</td>
                    <td class="px-4 py-3">${t['Agent Name'] || 'N/A'}</td>
                    <td class="px-4 py-3 truncate max-w-xs text-xs">${t.Subject}</td>
                `;
                tbody.appendChild(tr);
            });
        }

        function resetFilters() {
            document.getElementById('filterMonth').value = 'all';
            document.getElementById('filterAgentGroup').value = 'all';
            document.getElementById('filterActionBy').value = 'all';
            applyFilters();
        }

        init();
    </script>
</body>

