+                <p class="text-xs font-bold text-slate-500 uppercase">Total Logs Found</p>
+                <h2 class="text-3xl font-bold text-blue-400 mt-1" id="filteredTotal">0</h2>
+                <p class="text-[10px] text-slate-500 mt-1">Out of <span id="globalTotal">0</span> entries</p>
