        const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

        async function init() {
            try {
                const response = await fetch('data.json');
                rawData = await response.json();
                document.getElementById('globalTotal').textContent = rawData.length.toLocaleString();
                document.getElementById('lastSync').textContent = new Date().toLocaleString();

                populateFilters();
                applyFilters();

                ['filterMonth', 'filterAgentGroup', 'filterActionBy'].forEach(id => {
                    document.getElementById(id).addEventListener('change', applyFilters);
                });
            } catch (err) {
                console.error("Critical Failure:", err);
            }
        }

        function populateFilters() {
            const months = new Set();
            const groups = new Set();
            const names = new Set();

            rawData.forEach(t => {
                if (t['Resolved Date']) {
                    const d = new Date(t['Resolved Date']);
                    months.add(`${d.getFullYear()}-${(d.getMonth() + 1).toString().padStart(2, '0')}`);
                }
                if (t['Agent Name']) groups.add(t['Agent Name']);
                if (t['Action by']) names.add(t['Action by']);
            });

            const fill = (id, items, label) => {
                const el = document.getElementById(id);
                el.innerHTML = `<option value="all">Global ${label}</option>`;
                Array.from(items).sort().forEach(i => {
                    const opt = document.createElement('option');
                    opt.value = i;
                    if (id === 'filterMonth') {
                        const [y, m] = i.split('-');
                        opt.textContent = `${monthNames[m-1]} ${y}`;
                    } else {
                        opt.textContent = i;
                    }
                    el.appendChild(opt);
                });
            };

            fill('filterMonth', months, 'Period');
            fill('filterAgentGroup', groups, 'Groups');
            fill('filterActionBy', names, 'Personnel');
        }

        function applyFilters() {
            const m = document.getElementById('filterMonth').value;
            const ag = document.getElementById('filterAgentGroup').value;
            const ab = document.getElementById('filterActionBy').value;

            filteredData = rawData.filter(t => {
                let match = true;
                if (m !== 'all') {
                    const d = new Date(t['Resolved Date']);
                    if (`${d.getFullYear()}-${(d.getMonth() + 1).toString().padStart(2, '0')}` !== m) match = false;
                }
                if (ag !== 'all' && t['Agent Name'] !== ag) match = false;
                if (ab !== 'all' && t['Action by'] !== ab) match = false;
                return match;
            });

            updateUI();
        }

        function updateUI() {
            document.getElementById('filteredTotal').textContent = filteredData.length.toLocaleString();

            // Stats
            const personnel = new Set(filteredData.map(t => t['Action by'])).size;
            document.getElementById('activePersonnel').textContent = personnel;

            const score = Math.min(100, Math.max(70, 100 - (filteredData.length / 500)));
            document.getElementById('healthScore').textContent = score.toFixed(0);

            // AI Insight Logic
            const topBU = getTop(filteredData, 'BU Name');
            const topAgent = getTop(filteredData, 'Action by');
            document.getElementById('aiInsight').textContent = `Currently, support activity is most concentrated in ${topBU}. Performance leader is ${topAgent}, managing ${((filteredData.filter(x=>x['Action by']===topAgent).length / filteredData.length)*100).toFixed(1)}% of filtered workload.`;

            renderCharts();
            renderPainPoints();
            renderTable();
        }

        function getTop(data, key) {
            const counts = {};
            data.forEach(t => counts[t[key]] = (counts[t[key]] || 0) + 1);
            return Object.entries(counts).sort((a,b) => b[1]-a[1])[0]?.[0] || 'N/A';
        }

        function renderCharts() {
            // Trend
            const trendMap = {};
            filteredData.forEach(t => {
                const d = t['Resolved Date'].split(' ')[0];
                trendMap[d] = (trendMap[d] || 0) + 1;
            });
            const tLabels = Object.keys(trendMap).sort();

            updateChart('trendChart', 'line', tLabels, tLabels.map(l => trendMap[l]), '#3b82f6');

            // Performance
            const perfMap = {};
            filteredData.forEach(t => {
                const n = t['Action by'] || 'Unknown';
                perfMap[n] = (perfMap[n] || 0) + 1;
            });
            const pSorted = Object.entries(perfMap).sort((a,b) => b[1]-a[1]).slice(0, 8);

            updateChart('performanceChart', 'bar', pSorted.map(x=>x[0]), pSorted.map(x=>x[1]), '#fbbf24', true);
        }

        function updateChart(id, type, labels, data, color, horizontal = false) {
            if (charts[id]) charts[id].destroy();
            charts[id] = new Chart(document.getElementById(id), {
                type: type,
                data: {
                    labels: labels,
                    datasets: [{
                        data: data,
                        borderColor: color,
                        backgroundColor: type === 'line' ? color + '11' : color + 'aa',
                        fill: true,
                        tension: 0.4,
                        borderRadius: 10
                    }]
                },
                options: {
                    indexAxis: horizontal ? 'y' : 'x',
                    maintainAspectRatio: false,
                    plugins: { legend: { display: false } },
                    scales: {
                        x: { grid: { display: false }, ticks: { color: '#64748b', font: { size: 10 } } },
                        y: { grid: { color: 'rgba(255,255,255,0.05)' }, ticks: { color: '#64748b' } }
                    }
                }
            });
        }

        function renderPainPoints() {
            const points = [
                { key: 'Notepad', label: 'Encoding Issues (Thai/Notepad)', color: 'red' },
                { key: 'Oracle', label: 'Oracle IE Mode Compatibility', color: 'blue' },
                { key: 'Hardware', label: 'Aging Assets / Laptop Refresh', color: 'amber' }
            ];

            const list = document.getElementById('painPointsList');
            list.innerHTML = '';
            points.forEach(p => {
                const count = filteredData.filter(t => JSON.stringify(t).includes(p.key)).length;
                const pct = ((count / filteredData.length) * 100).toFixed(1);

                const item = document.createElement('div');
                item.className = 'flex items-center gap-6';
                item.innerHTML = `
                    <div class="w-48 text-sm font-bold text-slate-300 truncate">${p.label}</div>
                    <div class="flex-1 bg-slate-800 h-2 rounded-full overflow-hidden">
                        <div class="bg-${p.color}-500 h-full" style="width: ${pct}%"></div>
                    </div>
                    <div class="w-16 text-right text-xs font-mono text-slate-500">${pct}%</div>
                `;
                list.appendChild(item);
            });
        }

        function renderTable() {
            const tbody = document.getElementById('logTableBody');
            tbody.innerHTML = '';
            filteredData.slice(0, 50).forEach(t => {
                const tr = document.createElement('tr');
                tr.className = 'border-b border-slate-900 hover:bg-slate-800/20 transition-colors group';
                tr.innerHTML = `
                    <td class="py-4 text-xs font-mono">${t['Resolved Date'] || 'N/A'}</td>
                    <td class="py-4 font-bold text-white">${t['Action by'] || 'N/A'}</td>
                    <td class="py-4"><span class="px-2 py-1 bg-slate-800 rounded text-[10px]">${t['Agent Name']}</span></td>
                    <td class="py-4 text-xs italic line-clamp-1 max-w-sm">${t.Subject}</td>
                    <td class="py-4 text-right font-mono text-slate-600 text-xs">${t.ID}</td>
                `;
                tbody.appendChild(tr);
            });
        }

        function resetFilters() {
            document.querySelectorAll('select').forEach(s => s.value = 'all');
            applyFilters();
        }

        init();
    </script>
