    <script>
        let rawData = [];
...

        async function init() {
            try {
                const response = await fetch('data.json');
                rawData = await response.json();
                populateFilters();
                applyFilters();
                ['filterMonth', 'filterActionBy'].forEach(id => {
                    document.getElementById(id).addEventListener('change', applyFilters);
                });
            } catch (err) {
                console.error("Init Error:", err);
            }
        }

        function populateFilters() {
            const months = new Set();
            const names = new Set();
            rawData.forEach(t => {
                if (t['Resolved Date']) {
                    const d = new Date(t['Resolved Date']);
                    months.add(`${d.getFullYear()}-${(d.getMonth() + 1).toString().padStart(2, '0')}`);
                }
                if (t['Action by']) names.add(t['Action by']);
            });

            const fill = (id, items, label) => {
                const el = document.getElementById(id);
                el.innerHTML = `<option value="all">All ${label}</option>`;
                Array.from(items).sort().forEach(i => {
                    const opt = document.createElement('option');
                    opt.value = i;
                    opt.textContent = id === 'filterMonth' ? `${monthNames[i.split('-')[1]-1]} ${i.split('-')[0]}` : i;
                    el.appendChild(opt);
                });
            };
            fill('filterMonth', months, 'Months');
            fill('filterActionBy', names, 'Personnel');
        }

        function applyFilters() {
            const m = document.getElementById('filterMonth').value;
            const ab = document.getElementById('filterActionBy').value;

            filteredData = rawData.filter(t => {
                let match = true;
                if (m !== 'all') {
                    const d = new Date(t['Resolved Date']);
                    if (`${d.getFullYear()}-${(d.getMonth() + 1).toString().padStart(2, '0')}` !== m) match = false;
                }
                if (ab !== 'all' && t['Action by'] !== ab) match = false;
                return match;
            });

            updateUI();
        }

        function updateUI() {
            document.getElementById('totalLogsBadge').textContent = `${filteredData.length.toLocaleString()} Logs`;
            renderMethodChart();
            renderPerformanceChart();
            renderRootCauses();
            renderTable();
        }

        function renderMethodChart() {
            const map = {};
            filteredData.forEach(t => {
                const m = t['Resolution Method'] || 'N/A';
                map[m] = (map[m] || 0) + 1;
            });
            const labels = Object.keys(map);
            const data = Object.values(map);

            if (charts.method) charts.method.destroy();
            charts.method = new Chart(document.getElementById('methodChart'), {
                type: 'doughnut',
                data: {
                    labels: labels,
                    datasets: [{
                        data: data,
                        backgroundColor: ['#3b82f6aa', '#22c55eaa', '#fbbf24aa', '#ef4444aa', '#a78bfaaa'],
                        borderColor: '#1e293b',
                        borderWidth: 2
                    }]
                },
                options: {
                    maintainAspectRatio: false,
                    plugins: { legend: { position: 'bottom', labels: { color: '#64748b', font: { size: 10 } } } }
                }
            });
        }

        function renderPerformanceChart() {
            const map = {};
            filteredData.forEach(t => {
                const n = t['Action by'] || 'Unknown';
                map[n] = (map[n] || 0) + 1;
            });
            const sorted = Object.entries(map).sort((a,b) => b[1]-a[1]).slice(0, 10);

            if (charts.perf) charts.perf.destroy();
            charts.perf = new Chart(document.getElementById('perfChart'), {
                type: 'bar',
                data: {
                    labels: sorted.map(x => x[0]),
                    datasets: [{
                        data: sorted.map(x => x[1]),
                        backgroundColor: '#22c55eaa',
                        borderRadius: 6
                    }]
                },
                options: {
                    indexAxis: 'y',
                    maintainAspectRatio: false,
                    plugins: { legend: { display: false } },
                    scales: {
                        x: { grid: { color: 'rgba(255,255,255,0.05)' }, ticks: { color: '#64748b' } },
                        y: { grid: { display: false }, ticks: { color: '#f8fafc', font: { size: 10 } } }
                    }
                }
            });
        }

        function renderRootCauses() {
            const causeMap = {};
            filteredData.forEach(t => {
                const notes = t['Resolution Notes'] || '';
                // Extract Cause :: ...
                const match = notes.match(/Cause\s*::\s*([^,]+)/i);
                if (match && match[1]) {
                    const causeText = match[1].trim().toLowerCase();
                    // Basic Normalization
                    let normalized = causeText;
                    if (normalized.includes('สัญญา')) normalized = 'Staff Contract Expired / Extend';
                    if (normalized.includes('notepad') || normalized.includes('ภาษา')) normalized = 'Thai Character Encoding Issue (Notepad)';
                    if (normalized.includes('network') || normalized.includes('disconnected')) normalized = 'Network Connection Lost';
                    if (normalized.includes('password') || normalized.includes('login')) normalized = 'Login / Password Issue';
                    if (normalized.includes('ie mode') || normalized.includes('edge')) normalized = 'Browser (IE Mode) Compatibility';

                    causeMap[normalized] = (causeMap[normalized] || 0) + 1;
                }
            });

            const topCauses = Object.entries(causeMap).sort((a,b) => b[1]-a[1]).slice(0, 10);
            const list = document.getElementById('rootCauseList');
            list.innerHTML = '';

            topCauses.forEach(([cause, count], i) => {
                const item = document.createElement('div');
                item.className = 'flex justify-between items-center bg-slate-800/40 p-3 rounded-xl border border-slate-700/50 hover:border-red-500/30 transition-all';
                item.innerHTML = `
                    <div class="flex items-center gap-3 overflow-hidden">
                        <span class="text-xs font-bold text-slate-500">${i+1}.</span>
                        <p class="text-sm text-slate-300 truncate capitalize">${cause}</p>
                    </div>
                    <div class="flex items-center gap-2">
                        <span class="text-xs font-bold text-red-400">${count}</span>
                        <span class="text-[10px] text-slate-600 font-mono">Hits</span>
                    </div>
                `;
                list.appendChild(item);
            });
        }

        function renderTable() {
            const tbody = document.getElementById('mainTableBody');
            tbody.innerHTML = '';
            filteredData.slice(0, 100).forEach(t => {
                const tr = document.createElement('tr');
                tr.className = 'border-b border-slate-800 hover:bg-slate-800/30 transition-colors';
                tr.innerHTML = `
                    <td class="py-3 px-2 font-mono text-[10px] text-slate-500">${t.ID}</td>
                    <td class="py-3 px-2 font-bold text-white">${t['Action by'] || 'N/A'}</td>
                    <td class="py-3 px-2"><span class="px-2 py-0.5 bg-blue-500/10 text-blue-400 rounded text-[10px] border border-blue-500/20">${t['Resolution Method'] || 'N/A'}</span></td>
                    <td class="py-3 px-2 font-medium text-slate-300 truncate max-w-[200px]">${t.Subject}</td>
                    <td class="py-3 px-2 text-[10px] text-slate-500 line-clamp-2 italic">${t['Resolution Notes'] || 'N/A'}</td>
                `;
                tbody.appendChild(tr);
            });
        }

        function resetFilters() {
            document.getElementById('filterMonth').value = 'all';
            document.getElementById('filterActionBy').value = 'all';
            applyFilters();
        }

        init();
    </script>
